import { O11yMetrics } from '../common/metric';
/**
 * Represents the ActivatorTelemetry class which extends O11yMetrics.
 * This class provides metrics related to the activator's behavior.
 * @class
 * @extends {O11yMetrics}
 */
export default class ActivatorTelemetry extends O11yMetrics {
    /**
     * Represents the metric `activator.check_service`.
     * This metric represents the number of times the activator checks if the service should be active.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _checkServiceMetric;
    /**
     * Represents the metric `activator.check_service.failed`.
     * This metric represents the number of times the activator checks if the service should be active and fails.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _checkServiceFailedMetric;
    /**
     * Represents the metric `activator.check_service.not_found`.
     * This metric represents the number of times the activator checks if the service should be active and receives a 404 status response.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _checkServiceNotFoundMetric;
    /**
     * Represents the metric `activator.check_service.succeed`.
     * This metric represents the number of times the activator checks if the service should be active and succeeds.
     * @type {Counter}
     * @private
     * @readonly
     */
    private readonly _checkServiceSucceedMetric;
    /**
     * Represents the metric `activator.is_active`.
     * This metric represents if the service is active, metric with value 1, or not, metric with value 0.
     * @type {ObservableGauge}
     * @private
     * @readonly
     */
    private readonly _activatorStatusMetric;
    /**
     * Creates an instance of ActivatorTelemetry.
     */
    constructor();
    /**
     * Increments the metric `activator.check_service` by 1.
     * @returns {void}
     */
    incrementCheckServiceMetric(): void;
    /**
     * Increments the metric `activator.check_service.failed` by 1.
     * @returns {void}
     */
    incrementCheckServiceFailedMetric: () => void;
    /**
     * Increments the metric `activator.check_service.not_found` by 1.
     * @returns {void}
     */
    incrementCheckServiceNotFoundMetric: () => void;
    /**
     * Increments the metric `activator.check_service.succeed` by 1.
     * @returns {void}
     */
    incrementCheckServiceSucceedMetric: () => void;
    /**
     * Creates an observer for the return of the {@link isActive}.
     * Changes the metric `activator.is_active` with the value 1 if the service is active, otherwise 0.
     * @param {() => boolean} isActive A function that returns true if the service is active, otherwise false.
     * @returns {void}
     */
    observeActivatorStatusMetric: (isActive: () => boolean) => void;
}
